// 取出任務資料（n8n 會把 POST body 放在 body 或直接展開）
const d = $input.item.json.body ?? $input.item.json;

// 回傳完整任務資料供後續節點使用
return {
  event:          d.event          ?? 'task_assigned',
  task_id:        d.task_id,
  task_title:     d.task_title      ?? '（未命名任務）',
  description:    d.description     ?? null,
  assignee:       d.assignee        ?? null,
  assignee_email: d.assignee_email  ?? null,
  priority:       d.priority        ?? null,
  status:         d.status          ?? null,
  project_name:   d.project_name    ?? null,
  start_date:     d.start_date      ?? null,
  due_date:       d.due_date        ?? null,
  has_email:      !!(d.assignee_email && d.assignee_email.includes('@')),
};

// 組裝寄件內容
const d = $input.item.json;

const dateRange = d.start_date && d.due_date
  ? `${d.start_date} → ${d.due_date}`
  : (d.due_date ?? d.start_date ?? null);

const rows = [
  ['任務', d.task_title],
  d.project_name ? ['專案', d.project_name]  : null,
  d.priority     ? ['優先級', d.priority]     : null,
  d.status       ? ['狀態', d.status]        : null,
  dateRange      ? ['日程', dateRange]        : null,
].filter(Boolean);

const tableRows = rows.map(
  ([label, val]) =>
    `<tr><td style="padding:6px 12px;background:#f3f4f6;font-weight:600;white-space:nowrap">${label}</td>` +
    `<td style="padding:6px 12px">${val}</td></tr>`
).join('');

return {
  to:      d.assignee_email,
  subject: `[PM System] 任務指派通知：${d.task_title}`,
  html: `
<p>您好 ${d.assignee ?? ''}，</p>
<p>您已被指派以下任務，請確認並盡快處理：</p>
<table style="border-collapse:collapse;width:100%;max-width:520px">${tableRows}</table>
${d.description ? `<p style="margin-top:12px;color:#374151"><b>說明：</b>${d.description}</p>` : ''}
<p style="margin-top:16px;color:#9ca3af;font-size:12px">此信由 PM System 自動發送，請勿直接回覆。</p>
  `.trim(),
};
